const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security middleware ---

// Set secure HTTP headers (X-Content-Type-Options, CSP, HSTS, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Global rate limiter — 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Remove the X-Powered-By header (also done by helmet, but explicit is good)
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  // Example: support optional filtering by name with input validation
  const { name } = req.query;
  if (name !== undefined) {
    if (typeof name !== 'string' || name.length > 100) {
      return res.status(400).json({ error: 'Invalid "name" query parameter.' });
    }
    const sanitized = name.replace(/[<>"'&]/g, ''); // strip dangerous chars
    const filtered = users.filter(
      (u) => u.name.toLowerCase().includes(sanitized.toLowerCase())
    );
    return res.json(filtered);
  }

  return res.json(users);
});

// --- 404 handler for unknown routes ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// --- Global error handler ---
// Express identifies error handlers by their 4-parameter signature.
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log the full error internally but never expose it to the client
  console.error('Unhandled error:', err);
  res.status(err.status || 500).json({
    error:
      process.env.NODE_ENV === 'production'
        ? 'Internal server error.'
        : err.message,
  });
});

// --- Start server ---
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

