## Current Issues

### 1. **No Body Parser / Input Handling**
The app doesn't parse request bodies, which means if you add POST/PUT routes later, there's no input handling — and no validation layer.

### 2. **No Security Headers**
There's no `helmet` or manual security headers. Responses are sent without protections against XSS, clickjacking, MIME sniffing, etc.

### 3. **No Rate Limiting**
The endpoints are open to abuse — no rate limiting is configured.

### 4. **No Global Error Handler**
If any route throws an unexpected error, Express will return a default HTML error page that leaks stack traces (especially in development).

### 5. **No Input Validation on `/users`**
While `/users` currently returns static data, there's no query parameter validation. If this evolves to accept `?id=` or `?name=`, unvalidated input could lead to injection issues.

### 6. **Sensitive Data Exposure**
The `/users` endpoint returns email addresses with no authentication or authorization check.

### 7. **No CORS Configuration**
No CORS policy is set, so the default behavior depends on the client/browser. This should be explicitly configured.

---

## Recommended Improvements

Here's what a hardened version would look like:

```js
const express = require('express');
const helmet = require('helmet');       // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting
const { query, validationResult } = require('express-validator'); // Input validation

const app = express();

// --- Security middleware ---
app.use(helmet());                      // Sets secure HTTP headers
app.use(express.json({ limit: '1kb' })); // Parse JSON with size limit to prevent large payload attacks
app.use(express.urlencoded({ extended: false, limit: '1kb' }));

// --- Rate limiting ---
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 100,                   // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Disable fingerprinting ---
app.disable('x-powered-by'); // helmet does this too, but belt-and-suspenders

// --- Routes ---

app.get('/health', (req, res) => {
  // Don't leak server internals — return minimal info
  res.json({ status: 'ok' });
});

app.get('/users',
  // Example: validate optional query params
  query('id').optional().isInt({ min: 1 }).toInt(),
  query('name').optional().isString().trim().escape(),
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    try {
      // In production: authenticate first, then filter fields based on authorization
      const users = [
        { id: 1, name: 'Alice' },  // Removed email — don't expose PII by default
        { id: 2, name: 'Bob' },
      ];
      res.json(users);
    } catch (err) {
      next(err); // Forward to global error handler
    }
  }
);

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler (must have 4 params) ---
app.use((err, req, res, next) => {
  console.error(err.stack); // Log full error server-side
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'   // Don't leak details in production
      : err.message,
  });
});

// --- Startup ---
const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

